import React, { useState } from "react";

const ProductSuggester = () => {
  const [selectedItems, setSelectedItems] = useState([]);
  const [suggestions, setSuggestions] = useState([]);

  const products = ["Laptop", "Mouse", "Keyboard", "Headphones", "Monitor"];

  const toggleSelection = (product) => {
    setSelectedItems((prev) =>
      prev.includes(product)
        ? prev.filter((p) => p !== product)
        : [...prev, product]
    );
  };

  const getSuggestions = async () => {
    try {
      const response = await fetch("http://localhost:3000/api/suggest", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ selectedItems }),
      });

      if (!response.ok) {
        throw new Error("Failed to get suggestions");
      }

      const data = await response.json();
      setSuggestions(data);
    } catch (err) {
      console.error("Error fetching suggestions:", err);
    }
  };

  return (
    <div className="p-4">
      <h1 className="text-xl font-bold mb-4">Chọn sản phẩm:</h1>
      <div className="flex flex-wrap gap-2">
        {products.map((product) => (
          <button
            key={product}
            className={`border px-3 py-1 rounded ${
              selectedItems.includes(product)
                ? "bg-blue-500 text-white"
                : "bg-gray-200"
            }`}
            onClick={() => toggleSelection(product)}
          >
            {product}
          </button>
        ))}
      </div>

      <button
        onClick={getSuggestions}
        className="mt-4 bg-green-500 text-white px-4 py-2 rounded"
      >
        Gợi ý sản phẩm
      </button>

      <h2 className="mt-6 text-lg font-semibold">Gợi ý mua thêm:</h2>
      <ul className="list-disc pl-5">
        {suggestions.map((sug, index) => (
          <li key={index}>
            {sug.items.join(", ")} (Support: {(sug.support * 100).toFixed(2)}%)
          </li>
        ))}
        {suggestions.length === 0 && <li>Không có gợi ý.</li>}
      </ul>
    </div>
  );
};

export default ProductSuggester;
